class Solution:
    def countKReducibleNumbers(self, s: str, k: int) -> int:
        MOD = 10**9 + 7
        n = int(s, 2)
        dp = [[-1] * (k + 1) for _ in range(n + 1)]

        def count_set_bits(x):
            return bin(x).count('1')

        def dfs(x, k):
            if k == 0:
                return 0 if x != 1 else 1
            if x == 1:
                return 1
            if dp[x][k] != -1:
                return dp[x][k]
            set_bits = count_set_bits(x)
            dp[x][k] = (dfs(set_bits, k - 1) + dfs(x - 1, k)) % MOD
            return dp[x][k]

        res = 0
        for i in range(1, n):
            res = (res + dfs(i, k)) % MOD
        return res
